/* Suggested markup: <div class="uiwiki-measured-toast-queue" tabindex="0"><span>Measured Toast Queue</span></div> */
.uiwiki-measured-toast-queue {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-measured-toast-queue > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #d8f34e;
  animation: measured_toast_queue 1.8s ease-in-out infinite alternate;
}
.uiwiki-measured-toast-queue:hover,
.uiwiki-measured-toast-queue:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes measured_toast_queue {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-measured-toast-queue, .uiwiki-measured-toast-queue > span { animation: none; transition: none; }
}
